+    #[test]
+    fn adversarial_set_ex_zero() {
+        let mut store = Store::new();
+        let r = dispatch_argv(
+            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec(), b"EX".to_vec(), b"0".to_vec()],
+            &mut store, 1000,
+        );
+        assert!(r.is_err(), "SET EX 0 should error");
+    }
